package com.hospital.management.dao.impl;import com.hospital.management.dao.BillItemDao;import com.hospital.management.model.BillItem;import com.hospital.management.util.DatabaseConnectionManager;import java.sql.*;import java.util.*;public class BillItemDaoImpl implements BillItemDao{public List<BillItem>findByBillId(Long id)throws SQLException{if(id==null)return List.of();try(Connection c=DatabaseConnectionManager.getConnection();PreparedStatement s=c.prepareStatement("SELECT * FROM BILL_ITEMS WHERE BILL_ID=? ORDER BY BILL_ITEM_ID")){s.setLong(1,id);List<BillItem>x=new ArrayList<>();try(ResultSet r=s.executeQuery()){while(r.next())x.add(map(r));}return x;}}public long createItem(Connection c,BillItem i)throws SQLException{try(PreparedStatement s=c.prepareStatement("INSERT INTO BILL_ITEMS(BILL_ID,ITEM_TYPE,DESCRIPTION,QUANTITY,UNIT_PRICE,LINE_TOTAL)VALUES(?,?,?,?,?,?)",new String[]{"BILL_ITEM_ID"})){s.setLong(1,i.getBillId());s.setString(2,i.getItemType());s.setString(3,i.getDescription());s.setBigDecimal(4,i.getQuantity());s.setBigDecimal(5,i.getUnitPrice());s.setBigDecimal(6,i.getLineTotal());s.executeUpdate();try(ResultSet r=s.getGeneratedKeys()){if(r.next())return r.getLong(1);throw new SQLException("No bill item identifier returned");}}}public int deleteByBillId(Connection c,Long id)throws SQLException{try(PreparedStatement s=c.prepareStatement("DELETE FROM BILL_ITEMS WHERE BILL_ID=?")){s.setLong(1,id);return s.executeUpdate();}}private BillItem map(ResultSet r)throws SQLException{BillItem i=new BillItem();i.setBillItemId(r.getLong("BILL_ITEM_ID"));i.setBillId(r.getLong("BILL_ID"));i.setItemType(r.getString("ITEM_TYPE"));i.setDescription(r.getString("DESCRIPTION"));i.setQuantity(r.getBigDecimal("QUANTITY"));i.setUnitPrice(r.getBigDecimal("UNIT_PRICE"));i.setLineTotal(r.getBigDecimal("LINE_TOTAL"));Timestamp t=r.getTimestamp("CREATED_AT");i.setCreatedAt(t==null?null:t.toLocalDateTime());return i;}}
